namespace sv_916062d6394740a6b38b76aab74b2443.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Williams"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date)
    {
        // Stub: return fixed time slots regardless of doctor/date
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Reject email with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        // Reject "None" insurance with Dr. Smith (doesn't accept self-pay)
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Reject 10:00 AM as taken (race condition simulation)
        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_916062d6394740a6b38b76aab74b2443.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="@_model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    <h3>Step 1: Patient Information</h3>

    <div class="mb-3">
        <label class="form-label" for="patientName">Patient Name</label>
        <InputText id="patientName" class="form-control" @bind-Value="_model.PatientName" />
        <ValidationMessage For="() => _model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="email">Email</label>
        <InputText id="email" class="form-control" @bind-Value="_model.Email" />
        <ValidationMessage For="() => _model.Email" />
        @if (_serverErrors.ContainsKey("Email"))
        {
            <div class="validation-message">@_serverErrors["Email"]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label" for="phone">Phone</label>
        <InputText id="phone" class="form-control" @bind-Value="_model.Phone" />
        <ValidationMessage For="() => _model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="insurance">Insurance Provider</label>
        <InputSelect id="insurance" class="form-select" @bind-Value="_model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => _model.InsuranceProvider" />
    </div>

    @if (_showStep2)
    {
        <h3>Step 2: Appointment Details</h3>

        <div class="mb-3">
            <label class="form-label" for="doctor">Preferred Doctor</label>
            <InputSelect id="doctor" class="form-select" @bind-Value="_model.Doctor" @bind-Value:after="OnDoctorChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in _doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => _model.Doctor" />
            @if (_serverErrors.ContainsKey("Doctor"))
            {
                <div class="validation-message">@_serverErrors["Doctor"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="date">Date</label>
            <InputDate id="date" class="form-control" @bind-Value="_model.AppointmentDate" @bind-Value:after="OnDateChanged" />
            <ValidationMessage For="() => _model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="timeSlot">Time Slot</label>
            <InputSelect id="timeSlot" class="form-select" @bind-Value="_model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in _timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => _model.TimeSlot" />
            @if (_serverErrors.ContainsKey("TimeSlot"))
            {
                <div class="validation-message">@_serverErrors["TimeSlot"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="reason">Reason for Visit</label>
            <InputTextArea id="reason" class="form-control" @bind-Value="_model.ReasonForVisit" rows="3" />
            <ValidationMessage For="() => _model.ReasonForVisit" />
        </div>

        <button type="submit" class="btn btn-primary">Book Appointment</button>
    }
</EditForm>

@if (!_showStep2)
{
    <button class="btn btn-secondary mt-3" @onclick="CheckAvailability">Check Availability</button>
}

@if (_submitted)
{
    <div class="alert alert-success mt-3">Appointment booked successfully!</div>
}

@code {
    private AppointmentModel _model = new();
    private bool _showStep2;
    private bool _submitted;
    private List<string> _doctors = new();
    private List<string> _timeSlots = new();
    private Dictionary<string, string> _serverErrors = new();
    private EditContext? _editContext;

    protected override async Task OnInitializedAsync()
    {
        _doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task CheckAvailability()
    {
        _serverErrors.Clear();

        // Validate step 1 fields manually
        _editContext = new EditContext(_model);
        var validationMessages = new ValidationMessageStore(_editContext);

        bool step1Valid = true;

        if (string.IsNullOrWhiteSpace(_model.PatientName))
            step1Valid = false;
        if (string.IsNullOrWhiteSpace(_model.Email) || !IsValidEmail(_model.Email))
            step1Valid = false;
        if (string.IsNullOrWhiteSpace(_model.Phone))
            step1Valid = false;
        if (string.IsNullOrWhiteSpace(_model.InsuranceProvider))
            step1Valid = false;

        if (!step1Valid)
        {
            // Trigger validation display by forcing re-render with edit context validation
            _editContext.Validate();
            return;
        }

        _showStep2 = true;
    }

    private async Task OnDoctorChanged()
    {
        _serverErrors.Remove("Doctor");
        if (!string.IsNullOrEmpty(_model.Doctor) && _model.AppointmentDate.HasValue)
        {
            _timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                _model.Doctor, _model.AppointmentDate.Value);
        }
    }

    private async Task OnDateChanged()
    {
        if (!string.IsNullOrEmpty(_model.Doctor) && _model.AppointmentDate.HasValue)
        {
            _timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                _model.Doctor, _model.AppointmentDate.Value);
        }
    }

    private async Task HandleSubmit()
    {
        _serverErrors.Clear();
        _submitted = false;

        var errors = await AppointmentService.ValidatePatientAsync(
            _model.Email,
            _model.InsuranceProvider,
            _model.Doctor ?? "",
            _model.TimeSlot ?? "");

        if (errors.Count > 0)
        {
            _serverErrors = errors;
            return;
        }

        _submitted = true;
    }

    private static bool IsValidEmail(string email)
    {
        try
        {
            var addr = new System.Net.Mail.MailAddress(email);
            return addr.Address == email;
        }
        catch
        {
            return false;
        }
    }

    private class AppointmentModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Patient name is required")]
        public string PatientName { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Email is required")]
        [System.ComponentModel.DataAnnotations.EmailAddress(ErrorMessage = "Invalid email format")]
        public string Email { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Phone is required")]
        public string Phone { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Insurance provider is required")]
        public string InsuranceProvider { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Doctor is required")]
        public string? Doctor { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Date is required")]
        [FutureDate(ErrorMessage = "Date must be in the future")]
        public DateTime? AppointmentDate { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Time slot is required")]
        public string? TimeSlot { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Reason for visit is required")]
        [System.ComponentModel.DataAnnotations.MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters")]
        public string? ReasonForVisit { get; set; }
    }

    private class FutureDateAttribute : System.ComponentModel.DataAnnotations.ValidationAttribute
    {
        protected override System.ComponentModel.DataAnnotations.ValidationResult? IsValid(
            object? value, System.ComponentModel.DataAnnotations.ValidationContext validationContext)
        {
            if (value is DateTime date && date.Date <= DateTime.Today)
            {
                return new System.ComponentModel.DataAnnotations.ValidationResult(ErrorMessage);
            }
            return System.ComponentModel.DataAnnotations.ValidationResult.Success;
        }
    }
}

